patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index a337ab7410f7..eee32bf52c12 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -18181,7 +18181,7 @@ void BoUpSLP::computeMinimumValueSizes() {
       (NodeIdx == 0 && !VectorizableTree[NodeIdx]->UserTreeIndices.empty()) ||
       (NodeIdx != 0 && any_of(VectorizableTree[NodeIdx]->UserTreeIndices,
                               [NodeIdx](const EdgeInfo &EI) {
-                                return EI.UserTE->Idx > NodeIdx;
+                                return EI.UserTE && EI.UserTE->Idx > NodeIdx;
                               })))
     return;

@@ -18458,7 +18458,7 @@ void BoUpSLP::computeMinimumValueSizes() {
           NodeIdx < VectorizableTree.size() &&
           any_of(VectorizableTree[NodeIdx]->UserTreeIndices,
                  [](const EdgeInfo &EI) {
-                   return EI.EdgeIdx == 0 &&
+                   return EI.UserTE && EI.EdgeIdx == 0 &&
                           EI.UserTE->getOpcode() == Instruction::Trunc &&
                           !EI.UserTE->isAltShuffle();
                  });
@@ -18467,17 +18467,18 @@ void BoUpSLP::computeMinimumValueSizes() {
           any_of(
               VectorizableTree[NodeIdx]->UserTreeIndices,
               [&](const EdgeInfo &EI) {
-                return (EI.UserTE->hasState() &&
-                        EI.UserTE->getOpcode() == Instruction::ICmp) &&
-                       any_of(EI.UserTE->Scalars, [&](Value *V) {
-                         auto *IC = dyn_cast<ICmpInst>(V);
-                         return IC &&
-                                (IC->isSigned() ||
-                                 !isKnownNonNegative(IC->getOperand(0),
-                                                     SimplifyQuery(*DL)) ||
-                                 !isKnownNonNegative(IC->getOperand(1),
-                                                     SimplifyQuery(*DL)));
-                       });
+                if (!EI.UserTE || !EI.UserTE->hasState() ||
+                    EI.UserTE->getOpcode() != Instruction::ICmp)
+                  return false;
+                return any_of(EI.UserTE->Scalars, [&](Value *V) {
+                  auto *IC = dyn_cast<ICmpInst>(V);
+                  return IC &&
+                         (IC->isSigned() ||
+                          !isKnownNonNegative(IC->getOperand(0),
+                                              SimplifyQuery(*DL)) ||
+                          !isKnownNonNegative(IC->getOperand(1),
+                                              SimplifyQuery(*DL)));
+                });
               });
     }

